import{_ as t,o as e,c as i,a2 as s}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"1.1 种地","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 根据种地方式的不同，我们可以降种地的种类分为以下三种： ①直接种植②打捆种植③苗圃种植 ③苗圃种植 ①指的是：使用从种子商人处直接购买得到的种子来在自己的菜地里种 直接种植 植的行为。大部","frontmatter":{"title":"1.1 种地","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 根据种地方式的不同，我们可以降种地的种类分为以下三种： ①直接种植②打捆种植③苗圃种植 ③苗圃种植 ①指的是：使用从种子商人处直接购买得到的种子来在自己的菜地里种 直接种植 植的行为。大部","outline":"deep"},"headers":[],"relativePath":"life/1-1.md","filePath":"life/1-1.md","lastUpdated":null}'),p={name:"life/1-1.md"};function l(o,a,r,u,d,g){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="_1-1-种地" tabindex="-1">1.1 种地 <a id="s004-8bfc1783"></a> <a class="header-anchor" href="#_1-1-种地" aria-label="Permalink to &quot;1.1 种地 &lt;a id=&quot;s004-8bfc1783&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-1-1-种地的种类" tabindex="-1">1.1.1 种地的种类 <a id="s005-59aade40"></a> <a class="header-anchor" href="#_1-1-1-种地的种类" aria-label="Permalink to &quot;1.1.1 种地的种类 &lt;a id=&quot;s005-59aade40&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>根据种地方式的不同，我们可以降种地的种类分为以下三种：</p><p>①直接种植②打捆种植③苗圃种植</p><p>③苗圃种植</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_556.jpeg" alt="图示：1.1.1 种地的种类" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_564.jpeg" alt="图示：1.1.1 种地的种类" loading="lazy"></figure><h2 id="_1-1-2-直接种植" tabindex="-1">1.1.2 直接种植 <a id="s006-0c22e934"></a> <a class="header-anchor" href="#_1-1-2-直接种植" aria-label="Permalink to &quot;1.1.2 直接种植 &lt;a id=&quot;s006-0c22e934&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>①指的是：使用从种子商人处直接购买得到的种子来在自己的菜地里种</p><p>直接种植</p><p>植的行为。大部分情况下不推荐，仅在需要雷击木和树木副产品时使用这种方式。</p><h2 id="_1-1-3-打捆种植" tabindex="-1">1.1.3 打捆种植 <a id="s007-f69a962f"></a> <a class="header-anchor" href="#_1-1-3-打捆种植" aria-label="Permalink to &quot;1.1.3 打捆种植 &lt;a id=&quot;s007-f69a962f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>②指的是：在农夫制作台或者稻草人制作台（稻草人菜田里的那个稻草</p><p>打捆种植</p><p>人，可以直接无视权限使用别人的）花费劳动力将种子和蠕动的蚯蚓制作成捆后再在自己菜地里种植的行为。打捆种植是可以直接同捆复种的，可以避免重复种植的行为。</p><p>作物和树苗打捆后部分生长时间会变长，部分会变短，详情自己游戏内查看。</p><p>复种需要先手动种过一遍才可以进行，在第一次种下的捆成熟后，靠近后会出现</p><p>2 个选项，在背包内有对应的捆时，按G 便可收获+复种，如图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_571.jpeg" alt="图示：1.1.3 打捆种植" loading="lazy"></figure><h2 id="_1-1-4-苗圃种植" tabindex="-1">1.1.4 苗圃种植 <a id="s008-c0210d17"></a> <a class="header-anchor" href="#_1-1-4-苗圃种植" aria-label="Permalink to &quot;1.1.4 苗圃种植 &lt;a id=&quot;s008-c0210d17&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>③指的是使用房屋自带的</p><p>苗圃种植</p><p>苗圃来进行种植的行为。</p><p>苗圃种植需要先选择是农业还是</p><p>采集，F 是农业，G 是采集。如图所</p><p>示：</p><p>当然如果你按错了也可以按G 切换，如图所示：</p><p>当你选好种植类型后按F 可以唤出菜单栏，然后选你要种的就行。如图所示：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_572.jpeg" alt="图示：1.1.4 苗圃种植" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_579.jpeg" alt="图示：1.1.4 苗圃种植" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_580.jpeg" alt="图示：1.1.4 苗圃种植" loading="lazy"></figure><h2 id="_1-1-5-影响种地时间的因素" tabindex="-1">1.1.5 影响种地时间的因素 <a id="s009-a895904c"></a> <a class="header-anchor" href="#_1-1-5-影响种地时间的因素" aria-label="Permalink to &quot;1.1.5 影响种地时间的因素 &lt;a id=&quot;s009-a895904c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="影响作物成熟时间的因素" tabindex="-1">影响作物成熟时间的因素 <a id="s010-60fb8186"></a> <a class="header-anchor" href="#影响作物成熟时间的因素" aria-label="Permalink to &quot;影响作物成熟时间的因素 &lt;a id=&quot;s010-60fb8186&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>当玩家使用直接种植和打捆种植时，作物的成熟时间会受到种子适应气候与种植当地的气候影响。</p><p>如果气候合适，那么作物成熟后将不会变成打蔫的XXX。</p><p>如果气候不合适，那么作物成熟后将会变成打蔫的XXX。</p><p>将鼠标指针移动到打蔫的XXX 上时可以看到作物距离消失的时间，如果这个时间后仍未收割该作物的话，该作物会直接消失。</p><p>当玩家长时间未收割作物的时候，作物会变成变质的作物，这时候需要用有机肥和劳动力来救活农作物。</p><h3 id="影响收割作物时间的因素" tabindex="-1">影响收割作物时间的因素 <a id="s011-61fb69a3"></a> <a class="header-anchor" href="#影响收割作物时间的因素" aria-label="Permalink to &quot;影响收割作物时间的因素 &lt;a id=&quot;s011-61fb69a3&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>1）使用床睡觉后获得的生活相关活动施法时间减少的BUFF</p><p>2）熟练度时装自带的生活相关活动施法时间减少的效果</p><p>3）玩家熟练度减少施法时间</p><p>4）对应晨露时装在连续收割3 次后的减少施法时间的BUFF</p><p>5）家具提供的生活相关活动施法时间减少的BUFF</p><p>6）快速生产卷轴的BUFF</p><h2 id="_1-1-6-各种类种植方式的优缺点" tabindex="-1">1.1.6 各种类种植方式的优缺点 <a id="s012-66cfe60b"></a> <a class="header-anchor" href="#_1-1-6-各种类种植方式的优缺点" aria-label="Permalink to &quot;1.1.6 各种类种植方式的优缺点 &lt;a id=&quot;s012-66cfe60b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="优点" tabindex="-1">优点 <a id="s013-2678e9ca"></a> <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点 &lt;a id=&quot;s013-2678e9ca&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>①和②这两种种子方式都可以获得作物和副产物（树捆仅能获得静电叶片）。</p><p>②相较于①和③可以直接复种同种作物，在大量种植时可以节约时间。</p><p>③这种方式成熟时间较快且不受气候影响，长期放置不会打蔫。单个产量大种植活动花费时间较短。</p><h3 id="缺点" tabindex="-1">缺点 <a id="s014-f0a86bc8"></a> <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点 &lt;a id=&quot;s014-f0a86bc8&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>①和②成长时间较长，会受气候影响，对收割时间有要求。单个作物（捆）产量较为低下，种植活动花费时间较长。</p><p>③在收获时无法获得任何的副产物</p><h2 id="_1-1-7-种子的获取" tabindex="-1">1.1.7 种子的获取 <a id="s015-7eb8d6ae"></a> <a class="header-anchor" href="#_1-1-7-种子的获取" aria-label="Permalink to &quot;1.1.7 种子的获取 &lt;a id=&quot;s015-7eb8d6ae&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>种子的获取方式分为以下两种：</p><p>1）在菜单栏的生活点商店处或者生活点商人处购买（不推荐）</p><p>2）在种子和树苗商人处购买</p><p>种子和树苗商人会出现在：</p><p>1）住宅区附近的NPC 聚落处</p><p>2）相逢之庭的二楼</p>',63)])])}const f=t(p,[["render",l]]);export{c as __pageData,f as default};
